module seq_det_1011(
  input  clk, rst_n, in,
  output reg out
);
  localparam S0=0, S1=1, S2=2, S3=3, S4=4;
  reg [2:0] state, next;

  always @(posedge clk or negedge rst_n)
    if (!rst_n) state <= S0;
    else        state <= next;

  always @(*) begin
    next = S0; out = 0;
    case (state)
      S0: next = in ? S1 : S0;
      S1: next = in ? S1 : S2;
      S2: next = in ? S3 : S0;
      S3: next = in ? S4 : S2;
      S4: begin out = 1; next = in ? S1 : S2; end
      default: next = S0;
    endcase
  end
endmodule

