module rr_arbiter (
  input  logic       clk, rst_n,
  input  logic [3:0] req,
  output logic [3:0] gnt
);
  logic [1:0] ptr;
  logic [3:0] gnt_comb;
  int i;

  always_comb begin
    gnt_comb = 4'b0;
    for (i = 0; i < 4; i++) begin
      int idx;
      idx = (ptr + i) % 4;
      if (req[idx]) begin gnt_comb[idx] = 1'b1; break; end
    end
  end

  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) ptr <= 2'd0;
    else if (|gnt_comb)
      ptr <= (ptr == 2'd3) ? 2'd0 : ptr + 1'b1;
  end

  assign gnt = gnt_comb;
endmodule

