  task body();
    mem_txn txn;
    // 5 writes
    for (int i = 0; i < 5; i++) begin
      txn = mem_txn::type_id::create($sformatf("wr%0d", i));
      start_item(txn);
      assert(txn.randomize() with { write == 1; addr == i * 4; });
      finish_item(txn);
    end
    // 5 reads
